const results = $input.first().json.results || [];
const recipeName = $('Pick Recipe').first().json.recipe_name;

if (!results.length) throw new Error('No photos found for: ' + recipeName);

const imageUrl = results[0].urls.regular.split('?')[0] + '?w=1200&q=80';

return [{ json: { recipe_name: recipeName, image_url: imageUrl } }];

const raw = $input.first().json.text;

let content = raw
  .replace(/^```(?:markdown|md)?\n?/i, '')
  .replace(/\n?```\s*$/i, '')
  .trim();

const filenameMatch = content.match(/<!--\s*filename:\s*([\w-]+\.md)\s*-->/);
const filename = filenameMatch ? filenameMatch[1] : 'recipe-' + Date.now() + '.md';

const cleanContent = content
  .replace(/<!--\s*filename:[^>]+-->\n?/, '')
  .trim();

return [{ json: { filename, content: cleanContent, lang: 'en' } }];

const raw = $input.first().json.text;

let content = raw
  .replace(/^```(?:markdown|md)?\n?/i, '')
  .replace(/\n?```\s*$/i, '')
  .trim();

const filenameMatch = content.match(/<!--\s*filename:\s*([\w-]+\.md)\s*-->/);
const filename = filenameMatch ? filenameMatch[1] : 'recipe-' + Date.now() + '.md';

const cleanContent = content
  .replace(/<!--\s*filename:[^>]+-->\n?/, '')
  .trim();

return [{ json: { filename, content: cleanContent, lang: 'es' } }];

const items = $input.all();
const en = items.find(i => i.json.lang === 'en');
const es = items.find(i => i.json.lang === 'es');

if (!en || !es) {
  throw new Error('Missing language variant. Got: ' + JSON.stringify(items.map(i => i.json.lang)));
}

const recipeName = en.json.filename.replace('.md', '');

return [{
  json: {
    en_filename: en.json.filename,
    en_content: en.json.content,
    es_filename: es.json.filename,
    es_content: es.json.content,
    commit_message: 'feat: add ' + recipeName + ' recipe (EN + ES)'
  }
}];

const prepareData = $('Prepare Commit').first().json;
const branchInfo = $input.first().json;
// GET /branches/{branch} returns: { commit: { sha, commit: { tree: { sha } } } }
const parentCommitSha = branchInfo.commit.sha;
const currentTreeSha = branchInfo.commit.commit.tree.sha;
const defaultBranch = $('Get Repo Info').first().json.default_branch;

return [{
  json: {
    body: {
      base_tree: currentTreeSha,
      tree: [
        {
          path: 'recipes/en/' + prepareData.en_filename,
          mode: '100644',
          type: 'blob',
          content: prepareData.en_content
        },
        {
          path: 'recipes/es/' + prepareData.es_filename,
          mode: '100644',
          type: 'blob',
          content: prepareData.es_content
        }
      ]
    },
    parent_commit_sha: parentCommitSha,
    commit_message: prepareData.commit_message,
    default_branch: defaultBranch
  }
}];

const newTreeSha = $input.first().json.sha;
const parentSha = $('Build Create Tree Request').first().json.parent_commit_sha;
const message = $('Build Create Tree Request').first().json.commit_message;

return [{
  json: {
    body: {
      message: message,
      tree: newTreeSha,
      parents: [parentSha]
    }
  }
}];
